/**
 * A synthetic location.
 */
export interface LocationCollectionElement {
    /**
     * The list of location's capabilities.
     */
    capabilities?: string[];
    /**
     * The cloud provider where the location is hosted.
     *
     *  Only applicable to `PUBLIC` locations.
     */
    cloudPlatform?: 'ALIBABA' | 'AMAZON_EC2' | 'AZURE' | 'DYNATRACE_CLOUD' | 'GOOGLE_CLOUD' | 'INTEROUTE' | 'OTHER' | 'UNDEFINED';
    /**
     * Location's deployment type
     */
    deploymentType?: 'KUBERNETES' | 'OPENSHIFT' | 'STANDARD' | 'UNKNOWN';
    /**
     * The Dynatrace entity ID of the location.
     */
    entityId: string;
    /**
     * Location's city.
     */
    geoCity?: string;
    /**
     * Location's continent.
     */
    geoContinent?: string;
    /**
     * Location's country.
     */
    geoCountry?: string;
    /**
     * Location's latitude.
     */
    geoLatitude?: number;
    /**
     * The Dynatrace GeoLocation ID of the location.
     */
    geoLocationId: string;
    /**
     * Location's longitude.
     */
    geoLongitude?: number;
    /**
     * The list of IP addresses assigned to the location.
     *
     *  Only applicable to `PUBLIC` locations.
     */
    ips?: string[];
    /**
     * The timestamp of the last modification of the location.
     */
    lastModificationTimestamp?: number;
    /**
     * The name of the location.
     */
    name: string;
    /**
     * A list of synthetic nodes belonging to the location.
     *
     *  You can retrieve the list of available nodes with the [GET all nodes](https://dt-url.net/miy3rpl) call.
     */
    nodes?: string[];
    /**
     * The release stage of the location.
     */
    stage?: 'BETA' | 'COMING_SOON' | 'DELETED' | 'GA';
    /**
     * The status of the location.
     */
    status?: 'DISABLED' | 'ENABLED' | 'HIDDEN';
    /**
     * The type of the location.
     */
    type: 'CLUSTER' | 'PRIVATE' | 'PUBLIC';
}
